noncompliant:
// Noncompliant: Too deeply nested control structures
if (condition1) {
    if (condition2) {
        for (int i = 0; i < 10; i++) {
            if (condition3) {
                while (condition4) {
                    if (condition5) {
                        // 5 levels deep - too complex
                        doSomething();
                    }
                }
            }
        }
    }
}

compliant:
// Compliant: Properly structured with reduced nesting
if (condition1 && condition2) {
    processData();
}

void processData() {
    for (int i = 0; i < 10; i++) {
        if (shouldProcess(i)) {
            handleItem(i);
        }
    }
}

void handleItem(int item) {
    if (isValid(item)) {
        doSomething(item);
    }
}
